# ─── Помощник для подготовки полного словаря карты ───────────────────────────


def build_card_dict(idx: int, lesson: dict) -> dict:
    """Собрать полный словарь LessonCard из заготовки lesson + общих полей."""
    base = {
        "discipline": DISCIPLINE,
        "specialty": SPECIALTY,
        "course_number": COURSE,
        "group_name": GROUP,
        "students_count": STUDENTS,
        "duration": DURATION,
        "teacher_name": TEACHER,
        "teaching_methods_table": COMMON_METHODS,
        "resources": COMMON_RESOURCES,
    }
    base.update(lesson)
    return base


# ─── Основная функция: рендер и упаковка ─────────────────────────────────────


def main() -> None:
    if len(LESSONS) != 14:
        raise RuntimeError(f"Ожидалось 14 уроков, передано {len(LESSONS)}")

    docx_files: dict[str, bytes] = {}
    errors: list[str] = []

    for i, lesson_data in enumerate(LESSONS):
        n = i + 1
        d = START_DATE + timedelta(days=i * DATE_STEP_DAYS)

        # LessonCard ожидает поля lesson_number и date НЕ как часть Pydantic
        # (см. сам класс) — они идут в filename_pattern. Пробрасываем их
        # отдельно для имени файла; в саму модель попадают только её поля.
        card_dict = build_card_dict(n, lesson_data)
        try:
            card = LessonCard.model_validate(card_dict)
        except Exception as e:
            errors.append(f"Урок {n}: ошибка валидации Pydantic — {e}")
            continue

        # Параметры для имени файла (filename_pattern: "Урок_{lesson_number}_{discipline}.docx")
        filename_params = {
            "lesson_number": n,
            "discipline": DISCIPLINE,
        }
        fname_base = build_output_filename(LESSON_CARD, filename_params)
        # Префиксуем датой для удобной сортировки.
        fname = f"{d.strftime('%Y-%m-%d')}_{fname_base}"

        out_path = OUTPUT_DIR / fname
        try:
            render_document(LESSON_CARD, card, out_path)
            docx_files[fname] = out_path.read_bytes()
            print(f"[{n:2d}/14] OK  {fname}")
        except Exception as e:
            errors.append(f"Урок {n}: ошибка рендера — {e}")
            print(f"[{n:2d}/14] FAIL {e}")

    if errors:
        print("\n=== ОШИБКИ ===")
        for err in errors:
            print(" -", err)

    # ZIP
    zip_path = OUTPUT_DIR / "БД_09.01.03_14_уроков.zip"
    buf = io.BytesIO()
    with zipfile.ZipFile(buf, "w", zipfile.ZIP_DEFLATED) as zf:
        for name, data in docx_files.items():
            zf.writestr(name, data)
    zip_path.write_bytes(buf.getvalue())

    print(f"\nГотово: {len(docx_files)}/14 файлов")
    print(f"ZIP: {zip_path}")


if __name__ == "__main__":
    main()
